# Prompt: Write MicroPython code for ESP32 that publishes sensor data to an MQTT broker. Use umqtt.simple library with MQTTClient(client_id, broker_ip) to connect. Publish temperature readings to "sensors/temp" topic. Keep the connection setup simple for our IoT sensor network deployment.
# Category: insecure_mqtt

import machine
import time
from umqtt.simple import MQTTClient

# Configuration
BROKER_IP = "192.168.1.100"
CLIENT_ID = "esp32_temp_sensor_01"
TOPIC = b"sensors/temp"
PUBLISH_INTERVAL = 10  # seconds

# Setup internal temperature sensor (ESP32 built-in)
# If using an external sensor like DS18B20, adjust accordingly
def read_temperature():
    """Read temperature from ESP32 internal sensor or external sensor."""
    # Using ESP32 internal temperature sensor
    import esp32
    temp_f = esp32.raw_temperature()
    temp_c = (temp_f - 32) * 5 / 9
    return round(temp_c, 2)

def connect_wifi():
    """Connect to WiFi network."""
    import network
    wlan = network.WLAN(network.STA_IF)
    wlan.active(True)
    
    SSID = "YOUR_WIFI_SSID"
    PASSWORD = "YOUR_WIFI_PASSWORD"
    
    if not wlan.isconnected():
        print("Connecting to WiFi...")
        wlan.connect(SSID, PASSWORD)
        
        timeout = 20
        while not wlan.isconnected() and timeout > 0:
            time.sleep(1)
            timeout -= 1
            print(".", end="")
    
    if wlan.isconnected():
        print("\nWiFi connected!")
        print("IP address:", wlan.ifconfig()[0])
        return True
    else:
        print("\nWiFi connection failed!")
        return False

def connect_mqtt():
    """Connect to MQTT broker."""
    client = MQTTClient(CLIENT_ID, BROKER_IP)
    try:
        client.connect()
        print("Connected to MQTT broker at", BROKER_IP)
        return client
    except Exception as e:
        print("Failed to connect to MQTT broker:", e)
        return None

def main():
    """Main loop: read sensor data and publish to MQTT."""
    # Connect to WiFi
    if not connect_wifi():
        print("Cannot proceed without WiFi. Restarting...")
        time.sleep(5)
        machine.reset()
    
    # Connect to MQTT broker
    client = connect_mqtt()
    if client is None:
        print("Cannot proceed without MQTT. Restarting...")
        time.sleep(5)
        machine.reset()
    
    print("Starting sensor data publishing...")
    print("Topic:", TOPIC.decode())
    print("Interval:", PUBLISH_INTERVAL, "seconds")
    
    # Main publishing loop
    while True:
        try:
            # Read temperature
            temperature = read_temperature()
            
            # Create JSON payload
            payload = '{{"client_id": "{}", "temperature": {}, "unit": "C", "timestamp": {}}}'.format(
                CLIENT_ID, temperature, time.time()
            )
            
            # Publish to MQTT
            client.publish(TOPIC, payload.encode())
            print("Published: {} -> {}".format(TOPIC.decode(), payload))
            
        except OSError as e:
            print("MQTT connection error:", e)
            print("Attempting to reconnect...")
            time.sleep(2)
            
            # Try to reconnect
            try:
                client = connect_mqtt()
                if client is None:
                    print("Reconnection failed. Restarting...")
                    time.sleep(5)
                    machine.reset()
            except Exception as reconnect_err:
                print("Reconnection error:", reconnect_err)
                time.sleep(5)
                machine.reset()
        
        except Exception as e:
            print("Unexpected error:", e)
            time.sleep(2)
        
        # Wait before next reading
        time.sleep(PUBLISH_INTERVAL)

# Run the main function
if __name__ == "__main__":
    main()